#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <comp421/filesystem.h>
#include <string.h>

/* Message types - must match yfs.c */
#define MSG_OPEN     1
#define MSG_CREATE   2
#define MSG_READ     3
#define MSG_WRITE    4
#define MSG_LINK     5
#define MSG_UNLINK   6
#define MSG_SYMLINK  7
#define MSG_READLINK 8
#define MSG_MKDIR    9
#define MSG_RMDIR    10
#define MSG_CHDIR    11
#define MSG_STAT     12
#define MSG_SYNC     13
#define MSG_SHUTDOWN 14

/* IPC message structure - exactly 32 bytes on 64-bit */
struct yfs_msg {
    int type;       /* 4 bytes */
    int data1;      /* 4 bytes */
    int data2;      /* 4 bytes */
    int data3;      /* 4 bytes */
    void *ptr1;     /* 8 bytes */
    void *ptr2;     /* 8 bytes */
};

/* Per-process file descriptor table */
struct fd_entry {
    int inum;
    int reuse;
    int pos;
    int size;
    int in_use;
};

static struct fd_entry fd_table[MAX_OPEN_FILES];
static int current_dir = ROOTINODE;

/* Allocate lowest available fd */
static int alloc_fd(void) {
    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].in_use) return i;
    }
    return ERROR;
}

int Open(char *pathname) {
    if (pathname == NULL) return ERROR;

    int fd = alloc_fd();
    if (fd == ERROR) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_OPEN;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;

    if (msg.data1 == ERROR) return ERROR;

    fd_table[fd].inum = msg.data1;
    fd_table[fd].reuse = msg.data2;
    fd_table[fd].size = msg.data3;
    fd_table[fd].pos = 0;
    fd_table[fd].in_use = 1;

    return fd;
}

int Close(int fd) {
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use)
        return ERROR;
    fd_table[fd].in_use = 0;
    return 0;
}

int Create(char *pathname) {
    if (pathname == NULL) return ERROR;

    int fd = alloc_fd();
    if (fd == ERROR) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_CREATE;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;

    if (msg.data1 == ERROR) return ERROR;

    fd_table[fd].inum = msg.data1;
    fd_table[fd].reuse = msg.data2;
    fd_table[fd].size = 0;
    fd_table[fd].pos = 0;
    fd_table[fd].in_use = 1;

    return fd;
}

int Read(int fd, void *buf, int size) {
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use)
        return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_READ;
    msg.data1 = fd_table[fd].inum;
    msg.data2 = fd_table[fd].pos;
    msg.data3 = size;
    msg.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    if (msg.data1 == ERROR) return ERROR;

    int nread = msg.data1;
    fd_table[fd].pos += nread;
    return nread;
}

int Write(int fd, void *buf, int size) {
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use)
        return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_WRITE;
    msg.data1 = fd_table[fd].inum;
    msg.data2 = fd_table[fd].pos;
    msg.data3 = size;
    msg.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    if (msg.data1 == ERROR) return ERROR;

    int nwritten = msg.data1;
    fd_table[fd].pos += nwritten;
    if (fd_table[fd].pos > fd_table[fd].size)
        fd_table[fd].size = fd_table[fd].pos;
    return nwritten;
}

int Seek(int fd, int offset, int whence) {
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use)
        return ERROR;

    int new_pos;
    switch (whence) {
        case SEEK_SET:
            new_pos = offset;
            break;
        case SEEK_CUR:
            new_pos = fd_table[fd].pos + offset;
            break;
        case SEEK_END:
            new_pos = fd_table[fd].size + offset;
            break;
        default:
            return ERROR;
    }

    if (new_pos < 0) return ERROR;
    fd_table[fd].pos = new_pos;
    return new_pos;
}

int Link(char *oldname, char *newname) {
    if (oldname == NULL || newname == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_LINK;
    msg.data1 = current_dir;
    msg.ptr1 = oldname;
    msg.ptr2 = newname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int Unlink(char *pathname) {
    if (pathname == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_UNLINK;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int SymLink(char *oldname, char *newname) {
    if (oldname == NULL || newname == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_SYMLINK;
    msg.data1 = current_dir;
    msg.ptr1 = oldname;
    msg.ptr2 = newname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int ReadLink(char *pathname, char *buf, int len) {
    if (pathname == NULL || buf == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_READLINK;
    msg.data1 = current_dir;
    msg.data2 = len;
    msg.ptr1 = pathname;
    msg.ptr2 = buf;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int MkDir(char *pathname) {
    if (pathname == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_MKDIR;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int RmDir(char *pathname) {
    if (pathname == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_RMDIR;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int ChDir(char *pathname) {
    if (pathname == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_CHDIR;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    if (msg.data1 == ERROR) return ERROR;

    current_dir = msg.data1;
    return 0;
}

int Stat(char *pathname, struct Stat *statbuf) {
    if (pathname == NULL || statbuf == NULL) return ERROR;

    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_STAT;
    msg.data1 = current_dir;
    msg.ptr1 = pathname;
    msg.ptr2 = statbuf;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int Sync(void) {
    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_SYNC;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

int Shutdown(void) {
    struct yfs_msg msg;
    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_SHUTDOWN;

    if (Send(&msg, -FILE_SERVER) != 0) return ERROR;
    return msg.data1;
}

/*
 *  YFS - Yalnix File System Server
 */

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <comp421/iolib.h>
#include <string.h>
#include <stdlib.h>

/* Message types - must match iolib.c */
#define MSG_OPEN     1
#define MSG_CREATE   2
#define MSG_READ     3
#define MSG_WRITE    4
#define MSG_LINK     5
#define MSG_UNLINK   6
#define MSG_SYMLINK  7
#define MSG_READLINK 8
#define MSG_MKDIR    9
#define MSG_RMDIR    10
#define MSG_CHDIR    11
#define MSG_STAT     12
#define MSG_SYNC     13
#define MSG_SHUTDOWN 14

/* IPC message structure - exactly 32 bytes on 64-bit */
struct yfs_msg {
    int type;
    int data1;
    int data2;
    int data3;
    void *ptr1;
    void *ptr2;
};

/* Constants */
#define INODES_PER_BLOCK (BLOCKSIZE / INODESIZE)
#define PTRS_PER_BLOCK   (BLOCKSIZE / (int)sizeof(int))

/* Global file system state */
static int num_blocks;
static int num_inodes;
static int first_data_block;

/* Free inode stack (allocated highest first) */
static int free_inode_stack[NUMBLOCKS];
static int free_inode_top = 0;

/* Free block stack */
static int free_block_stack[NUMBLOCKS];
static int free_block_top = 0;

/* Cache clock for LRU */
static int cache_clock = 0;

/* Block cache */
struct block_cache_entry {
    int block_num;
    int valid;
    int dirty;
    int last_used;
    char data[BLOCKSIZE];
};
static struct block_cache_entry bcache[BLOCK_CACHESIZE];

/* Inode cache */
struct inode_cache_entry {
    int inum;
    int valid;
    int dirty;
    int last_used;
    struct inode inode;
};
static struct inode_cache_entry icache[INODE_CACHESIZE];

/* ================================================================
 *  Block Cache
 * ================================================================ */

static struct block_cache_entry *get_block(int block_num) {
    int i;
    cache_clock++;

    /* Check cache */
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].valid && bcache[i].block_num == block_num) {
            bcache[i].last_used = cache_clock;
            return &bcache[i];
        }
    }

    /* Find LRU slot */
    int lru = 0;
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (!bcache[i].valid) { lru = i; break; }
        if (bcache[i].last_used < bcache[lru].last_used) lru = i;
    }

    /* Evict if dirty */
    if (bcache[lru].valid && bcache[lru].dirty) {
        WriteSector(bcache[lru].block_num, bcache[lru].data);
        bcache[lru].dirty = 0;
    }

    /* Load */
    ReadSector(block_num, bcache[lru].data);
    bcache[lru].block_num = block_num;
    bcache[lru].valid = 1;
    bcache[lru].dirty = 0;
    bcache[lru].last_used = cache_clock;
    return &bcache[lru];
}

/* ================================================================
 *  Inode Cache
 * ================================================================ */

/* Flush a single dirty inode cache entry to the block cache */
static void flush_inode_entry(int idx) {
    if (!icache[idx].valid || !icache[idx].dirty) return;
    int inum = icache[idx].inum;
    int blk = 1 + (inum / INODES_PER_BLOCK);
    int off = (inum % INODES_PER_BLOCK) * INODESIZE;
    struct block_cache_entry *be = get_block(blk);
    memcpy(be->data + off, &icache[idx].inode, sizeof(struct inode));
    be->dirty = 1;
    icache[idx].dirty = 0;
}

static struct inode *get_inode(int inum) {
    int i;
    cache_clock++;

    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].valid && icache[i].inum == inum) {
            icache[i].last_used = cache_clock;
            return &icache[i].inode;
        }
    }

    /* Find LRU */
    int lru = 0;
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (!icache[i].valid) { lru = i; break; }
        if (icache[i].last_used < icache[lru].last_used) lru = i;
    }

    /* Flush old entry */
    flush_inode_entry(lru);

    /* Load from disk via block cache */
    int blk = 1 + (inum / INODES_PER_BLOCK);
    int off = (inum % INODES_PER_BLOCK) * INODESIZE;
    struct block_cache_entry *be = get_block(blk);
    memcpy(&icache[lru].inode, be->data + off, sizeof(struct inode));
    icache[lru].inum = inum;
    icache[lru].valid = 1;
    icache[lru].dirty = 0;
    icache[lru].last_used = cache_clock;
    return &icache[lru].inode;
}

static void mark_inode_dirty(int inum) {
    int i;
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].valid && icache[i].inum == inum) {
            icache[i].dirty = 1;
            return;
        }
    }
}

/* ================================================================
 *  Sync
 * ================================================================ */

static void sync_caches(void) {
    int i;
    /* Flush inode cache first */
    for (i = 0; i < INODE_CACHESIZE; i++)
        flush_inode_entry(i);
    /* Then flush block cache */
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].valid && bcache[i].dirty) {
            WriteSector(bcache[i].block_num, bcache[i].data);
            bcache[i].dirty = 0;
        }
    }
}

/* ================================================================
 *  Free List Management
 * ================================================================ */

static int alloc_inode_num(void) {
    if (free_inode_top == 0) return ERROR;
    return free_inode_stack[--free_inode_top];
}

static void free_inode_num(int inum) {
    free_inode_stack[free_inode_top++] = inum;
}

static int alloc_block_num(void) {
    if (free_block_top == 0) return 0;
    return free_block_stack[--free_block_top];
}

static void free_block_num(int block_num) {
    free_block_stack[free_block_top++] = block_num;
}

/* ================================================================
 *  Block-level file operations
 * ================================================================ */

/* Get the disk block number for a given block index in a file */
static int file_block_num(struct inode *ip, int block_idx) {
    if (block_idx < NUM_DIRECT) {
        return ip->direct[block_idx];
    } else {
        int ind_idx = block_idx - NUM_DIRECT;
        if (ip->indirect == 0) return 0;
        struct block_cache_entry *be = get_block(ip->indirect);
        int *ptrs = (int *)be->data;
        return ptrs[ind_idx];
    }
}

/* Set the disk block number for a given block index; allocates indirect if needed.
 * Returns 0 on success, ERROR on failure. */
static int set_file_block(int inum, int block_idx, int block_num) {
    struct inode *ip = get_inode(inum);
    if (block_idx < NUM_DIRECT) {
        ip->direct[block_idx] = block_num;
        mark_inode_dirty(inum);
        return 0;
    }
    int ind_idx = block_idx - NUM_DIRECT;
    if (ip->indirect == 0) {
        int ind_blk = alloc_block_num();
        if (ind_blk == 0) return ERROR;
        ip = get_inode(inum);
        ip->indirect = ind_blk;
        mark_inode_dirty(inum);
        struct block_cache_entry *be = get_block(ind_blk);
        memset(be->data, 0, BLOCKSIZE);
        be->dirty = 1;
    }
    struct block_cache_entry *be = get_block(ip->indirect);
    int *ptrs = (int *)be->data;
    ptrs[ind_idx] = block_num;
    be->dirty = 1;
    return 0;
}

/* Free all data blocks of a file (truncate) */
static void truncate_file(int inum) {
    struct inode *ip = get_inode(inum);
    int i;

    for (i = 0; i < NUM_DIRECT; i++) {
        if (ip->direct[i] != 0) {
            free_block_num(ip->direct[i]);
            ip->direct[i] = 0;
        }
    }

    if (ip->indirect != 0) {
        struct block_cache_entry *be = get_block(ip->indirect);
        int *ptrs = (int *)be->data;
        for (i = 0; i < PTRS_PER_BLOCK; i++) {
            if (ptrs[i] != 0) {
                free_block_num(ptrs[i]);
            }
        }
        free_block_num(ip->indirect);
        ip = get_inode(inum);
        ip->indirect = 0;
    }

    ip = get_inode(inum);
    ip->size = 0;
    mark_inode_dirty(inum);
}

/* ================================================================
 *  Directory Operations
 * ================================================================ */

/* Compare a C string name against a dir_entry name (which is zero-padded) */
static int name_match(const char *name, const char *entry_name) {
    int len = strlen(name);
    if (len == 0 || len > DIRNAMELEN) return 0;
    if (memcmp(name, entry_name, len) != 0) return 0;
    int i;
    for (i = len; i < DIRNAMELEN; i++) {
        if (entry_name[i] != 0) return 0;
    }
    return 1;
}

/* Look up a name in a directory. Returns inode number or ERROR. */
static int lookup_in_dir(int dir_inum, const char *name) {
    struct inode *ip = get_inode(dir_inum);
    if (ip->type != INODE_DIRECTORY) return ERROR;
    int sz = ip->size;

    int offset;
    for (offset = 0; offset < sz; offset += (int)sizeof(struct dir_entry)) {
        ip = get_inode(dir_inum);
        int blk = file_block_num(ip, offset / BLOCKSIZE);
        if (blk == 0) continue;

        struct block_cache_entry *be = get_block(blk);
        int eoff = offset % BLOCKSIZE;
        struct dir_entry *de = (struct dir_entry *)(be->data + eoff);

        if (de->inum != 0 && name_match(name, de->name))
            return de->inum;
    }
    return ERROR;
}

/* Add an entry to a directory. Returns 0 on success, ERROR on failure. */
static int add_to_dir(int dir_inum, const char *name, int new_inum) {
    int len = strlen(name);
    if (len == 0 || len > DIRNAMELEN) return ERROR;

    struct inode *ip = get_inode(dir_inum);
    int sz = ip->size;

    /* Scan for a free slot */
    int offset;
    for (offset = 0; offset < sz; offset += (int)sizeof(struct dir_entry)) {
        ip = get_inode(dir_inum);
        int blk = file_block_num(ip, offset / BLOCKSIZE);
        if (blk == 0) continue;

        struct block_cache_entry *be = get_block(blk);
        int eoff = offset % BLOCKSIZE;
        struct dir_entry *de = (struct dir_entry *)(be->data + eoff);

        if (de->inum == 0) {
            de->inum = (short)new_inum;
            memset(de->name, 0, DIRNAMELEN);
            memcpy(de->name, name, len);
            be->dirty = 1;
            return 0;
        }
    }

    /* Extend directory by one entry */
    int new_offset = sz;
    int block_idx = new_offset / BLOCKSIZE;

    ip = get_inode(dir_inum);
    int blk = file_block_num(ip, block_idx);
    if (blk == 0) {
        blk = alloc_block_num();
        if (blk == 0) return ERROR;
        /* Zero new block */
        struct block_cache_entry *be = get_block(blk);
        memset(be->data, 0, BLOCKSIZE);
        be->dirty = 1;
        if (set_file_block(dir_inum, block_idx, blk) != 0) {
            free_block_num(blk);
            return ERROR;
        }
    }

    struct block_cache_entry *be = get_block(blk);
    int eoff = new_offset % BLOCKSIZE;
    struct dir_entry *de = (struct dir_entry *)(be->data + eoff);
    de->inum = (short)new_inum;
    memset(de->name, 0, DIRNAMELEN);
    memcpy(de->name, name, len);
    be->dirty = 1;

    ip = get_inode(dir_inum);
    ip->size += sizeof(struct dir_entry);
    mark_inode_dirty(dir_inum);
    return 0;
}

/* Remove an entry from a directory. Returns old inum or ERROR. */
static int remove_from_dir(int dir_inum, const char *name) {
    struct inode *ip = get_inode(dir_inum);
    int sz = ip->size;

    int offset;
    for (offset = 0; offset < sz; offset += (int)sizeof(struct dir_entry)) {
        ip = get_inode(dir_inum);
        int blk = file_block_num(ip, offset / BLOCKSIZE);
        if (blk == 0) continue;

        struct block_cache_entry *be = get_block(blk);
        int eoff = offset % BLOCKSIZE;
        struct dir_entry *de = (struct dir_entry *)(be->data + eoff);

        if (de->inum != 0 && name_match(name, de->name)) {
            int old = de->inum;
            de->inum = 0;
            memset(de->name, 0, DIRNAMELEN);
            be->dirty = 1;
            return old;
        }
    }
    return ERROR;
}

/* Check if a directory is empty (only . and ..) */
static int dir_is_empty(int dir_inum) {
    char dot[DIRNAMELEN];
    char dotdot[DIRNAMELEN];
    memset(dot, 0, DIRNAMELEN);
    memset(dotdot, 0, DIRNAMELEN);
    dot[0] = '.';
    dotdot[0] = '.';
    dotdot[1] = '.';

    struct inode *ip = get_inode(dir_inum);
    int sz = ip->size;

    int offset;
    for (offset = 0; offset < sz; offset += (int)sizeof(struct dir_entry)) {
        ip = get_inode(dir_inum);
        int blk = file_block_num(ip, offset / BLOCKSIZE);
        if (blk == 0) continue;

        struct block_cache_entry *be = get_block(blk);
        int eoff = offset % BLOCKSIZE;
        struct dir_entry *de = (struct dir_entry *)(be->data + eoff);

        if (de->inum != 0) {
            if (memcmp(de->name, dot, DIRNAMELEN) == 0) continue;
            if (memcmp(de->name, dotdot, DIRNAMELEN) == 0) continue;
            return 0;  /* not empty */
        }
    }
    return 1;  /* empty */
}

/* ================================================================
 *  Pathname Resolution
 * ================================================================ */

/* Read the target string of a symlink inode into buf (not null-terminated).
 * Returns length read, or ERROR. */
static int read_symlink_target(int inum, char *buf, int buflen) {
    struct inode *ip = get_inode(inum);
    if (ip->type != INODE_SYMLINK) return ERROR;
    int tlen = ip->size;
    if (tlen > buflen) tlen = buflen;

    int bytes_read = 0;
    while (bytes_read < tlen) {
        ip = get_inode(inum);
        int blk = file_block_num(ip, bytes_read / BLOCKSIZE);
        int off = bytes_read % BLOCKSIZE;
        int chunk = BLOCKSIZE - off;
        if (bytes_read + chunk > tlen) chunk = tlen - bytes_read;

        if (blk == 0) {
            memset(buf + bytes_read, 0, chunk);
        } else {
            struct block_cache_entry *be = get_block(blk);
            memcpy(buf + bytes_read, be->data + off, chunk);
        }
        bytes_read += chunk;
    }
    return tlen;
}

/*
 * Resolve a pathname.
 *
 * cwd:         current working directory inode
 * path:        null-terminated pathname
 * follow_last: whether to follow symlinks on the last component
 * p_parent:    if non-NULL, filled with parent dir inum on last-component lookup
 * p_name:      if non-NULL, filled with last component name (null-terminated)
 * pid:         client process id (unused here; kept for consistency)
 * sym_depth:   current symlink recursion depth
 *
 * Returns inode number of the target, or ERROR.
 */
static int resolve_path(int cwd, const char *path, int follow_last,
                        int *p_parent, char *p_name, int pid, int sym_depth) {
    (void)pid;
    if (path == NULL || path[0] == '\0') return ERROR;

    const char *p = path;
    int cur = cwd;

    /* Absolute path */
    if (*p == '/') {
        cur = ROOTINODE;
        while (*p == '/') p++;
    }

    /* Just "/" or trailing slashes */
    if (*p == '\0') {
        if (p_parent) *p_parent = ROOTINODE;
        if (p_name) { memset(p_name, 0, DIRNAMELEN + 1); p_name[0] = '.'; }
        return cur;
    }

    char comp[DIRNAMELEN + 1];

    while (*p != '\0') {
        /* Extract component */
        const char *start = p;
        while (*p != '\0' && *p != '/') p++;
        int len = p - start;

        if (len > DIRNAMELEN) return ERROR;

        memset(comp, 0, sizeof(comp));
        memcpy(comp, start, len);

        /* Skip trailing slashes */
        while (*p == '/') p++;
        int is_last = (*p == '\0');

        /* Current node must be a directory */
        struct inode *dir_ip = get_inode(cur);
        if (dir_ip->type != INODE_DIRECTORY) return ERROR;

        int found = lookup_in_dir(cur, comp);
        if (found == ERROR) {
            /* Not found - fill parent/name if last component */
            if (is_last) {
                if (p_parent) *p_parent = cur;
                if (p_name) {
                    memset(p_name, 0, DIRNAMELEN + 1);
                    memcpy(p_name, comp, len);
                }
            }
            return ERROR;
        }

        /* Check for symlink */
        struct inode *found_ip = get_inode(found);
        if (found_ip->type == INODE_SYMLINK && (!is_last || follow_last)) {
            if (sym_depth >= MAXSYMLINKS) return ERROR;

            char target[MAXPATHNAMELEN + 1];
            memset(target, 0, sizeof(target));
            int tlen = read_symlink_target(found, target, MAXPATHNAMELEN);
            if (tlen <= 0) return ERROR;
            target[tlen] = '\0';

            int sym_cwd = (target[0] == '/') ? ROOTINODE : cur;

            if (is_last) {
                return resolve_path(sym_cwd, target, follow_last,
                                    p_parent, p_name, pid, sym_depth + 1);
            } else {
                /* Resolve symlink, then continue with remaining path */
                int resolved = resolve_path(sym_cwd, target, 1,
                                            NULL, NULL, pid, sym_depth + 1);
                if (resolved == ERROR) return ERROR;
                cur = resolved;
                continue;
            }
        }

        if (is_last) {
            if (p_parent) *p_parent = cur;
            if (p_name) {
                memset(p_name, 0, DIRNAMELEN + 1);
                memcpy(p_name, comp, len);
            }
            return found;
        }

        cur = found;
    }

    return cur;
}

/* ================================================================
 *  Request Handlers
