int main(int argc, char **argv) {
    if (Register(FILE_SERVER) != 0) {
        TracePrintf(0, "YFS: Failed to register\n");
        Exit(1);
    }

    init_fs();

    /* Fork and exec the first client process from argv[1] */
    if (argc > 1) {
        int cpid = Fork();
        if (cpid == 0) {
            Exec(argv[1], argv + 1);
            TracePrintf(0, "YFS: Exec of %s failed\n", argv[1]);
            Exit(1);
        }
    }

    struct yfs_msg msg;
    while (1) {
        int pid = Receive(&msg);
        if (pid == 0) break;  /* deadlock: no more clients */
        if (pid == ERROR) continue;

        int do_shutdown = 0;

        switch (msg.type) {
            case MSG_OPEN:     handle_open(&msg, pid);     break;
            case MSG_CREATE:   handle_create(&msg, pid);   break;
            case MSG_READ:     handle_read(&msg, pid);     break;
            case MSG_WRITE:    handle_write(&msg, pid);    break;
            case MSG_LINK:     handle_link(&msg, pid);     break;
            case MSG_UNLINK:   handle_unlink(&msg, pid);   break;
            case MSG_SYMLINK:  handle_symlink(&msg, pid);  break;
            case MSG_READLINK: handle_readlink(&msg, pid); break;
            case MSG_MKDIR:    handle_mkdir(&msg, pid);    break;
            case MSG_RMDIR:    handle_rmdir(&msg, pid);    break;
            case MSG_CHDIR:    handle_chdir(&msg, pid);    break;
            case MSG_STAT:     handle_stat(&msg, pid);     break;
            case MSG_SYNC:
                sync_caches();
                msg.data1 = 0;
                break;
            case MSG_SHUTDOWN:
                sync_caches();
                msg.data1 = 0;
                do_shutdown = 1;
                break;
            default:
                msg.data1 = ERROR;
                break;
        }

        Reply(&msg, pid);

        if (do_shutdown) {
            TracePrintf(0, "YFS: Shutting down\n");
            Exit(0);
        }
    }

    /* If we get here, it's a deadlock break - sync and exit */
    sync_caches();
    TracePrintf(0, "YFS: No more clients, shutting down\n");
    Exit(0);

    return 0;
}

